/**
 * Media Module Definition
 *
 * Core media management module for E-Menum.
 * Provides file upload, image processing, and asset management.
 *
 * This is a CORE module - it cannot be disabled.
 *
 * @module modules/_core/media/media.module
 *
 * @example
 * ```typescript
 * import { MediaModule } from '@/modules/_core/media/media.module';
 *
 * // Module is automatically discovered and loaded by ModuleLoader
 * // Access module instance via DI container
 * ```
 */

import { injectable, inject } from 'tsyringe';
import { TOKENS, registerSingleton, appContainer } from '@/core/kernel/container';
import type { ModuleInstance } from '@/core/kernel/module-loader';
import type { EventService } from '@/core/services/event.service';

import { MediaController } from '@/modules/_core/media/media.controller';
import { MediaService } from '@/modules/_core/media/media.service';
import { MediaRepository } from '@/modules/_core/media/media.repository';
import { mediaRoutes } from '@/modules/_core/media/media.routes';
import type { MediaModuleSettings } from '@/modules/_core/media/media.types';

// -----------------------------------------------------------------------------
// Module Types
// -----------------------------------------------------------------------------

/**
 * Media module context for lifecycle hooks
 */
export interface MediaModuleContext {
  /** Event service for pub/sub */
  events: EventService;
  /** Module settings */
  settings: MediaModuleSettings;
  /** Logger function */
  log: (message: string) => void;
}

/**
 * Media module hook definitions
 */
export interface MediaModuleHooks {
  /** Called before file upload */
  beforeUpload?: (data: { filename: string; mimeType: string; size: number }) => Promise<void>;
  /** Called after file upload */
  afterUpload?: (data: { mediaId: string; url: string }) => Promise<void>;
  /** Called before media deletion */
  beforeDelete?: (data: { mediaId: string }) => Promise<void>;
  /** Called after media deletion */
  afterDelete?: (data: { mediaId: string }) => Promise<void>;
  /** Called during image processing */
  onProcess?: (data: { mediaId: string; options: Record<string, unknown> }) => Promise<void>;
}

// -----------------------------------------------------------------------------
// Media Module Class
// -----------------------------------------------------------------------------

/**
 * Media Module
 *
 * Core module providing media management for E-Menum.
 * Handles file uploads, image processing, and asset storage.
 *
 * Features:
 * - File upload with validation
 * - Image optimization and resizing
 * - Thumbnail generation
 * - Multiple storage backends (local, S3, CDN)
 * - Media library management
 * - Bulk operations
 *
 * @example
 * ```typescript
 * // Module is automatically loaded by ModuleLoader
 * // Use MediaService for business logic
 * const mediaService = container.resolve('MediaService');
 * await mediaService.upload(orgId, { ... });
 * ```
 */
@injectable()
export class MediaModule implements ModuleInstance {
  // ---------------------------------------------------------------------------
  // Static Properties
  // ---------------------------------------------------------------------------

  /** Module ID */
  static readonly id = 'media';

  /** Module name */
  static readonly name = 'Media Module';

  /** Module version */
  static readonly version = '1.0.0';

  /** Is core module (cannot be disabled) */
  static readonly isCore = true;

  /** Module routes configuration */
  static readonly routes = mediaRoutes;

  /** Providers (services) to register */
  static readonly providers = [MediaService, MediaRepository];

  /** Controllers to register */
  static readonly controllers = [MediaController];

  // ---------------------------------------------------------------------------
  // Instance Properties
  // ---------------------------------------------------------------------------

  /** Module hooks registry */
  private hooks: MediaModuleHooks = {};

  /** Module initialized flag */
  private initialized = false;

  constructor(
    @inject(TOKENS.EventService) private readonly eventService: EventService
  ) {}

  // ---------------------------------------------------------------------------
  // ModuleInstance Lifecycle Hooks
  // ---------------------------------------------------------------------------

  /**
   * Called when module is loaded.
   * Registers services with DI container.
   */
  async onLoad(): Promise<void> {
    this.log('Loading media module...');

    // Register MediaRepository with DI container
    if (!appContainer.isRegistered('MediaRepository')) {
      registerSingleton('MediaRepository', MediaRepository);
    }

    // Register MediaService with DI container
    if (!appContainer.isRegistered('MediaService')) {
      registerSingleton('MediaService', MediaService);
    }

    this.log('Media module loaded');
  }

  /**
   * Called when module is enabled/activated.
   * Sets up event listeners and registers routes.
   */
  async onEnable(): Promise<void> {
    if (this.initialized) {
      this.log('Media module already initialized');
      return;
    }

    this.log('Enabling media module...');

    // Subscribe to relevant events
    this.setupEventListeners();

    this.initialized = true;
    this.log('Media module enabled');

    // Emit module activated event
    await this.eventService.emitCustom('module.activated', {
      moduleId: MediaModule.id,
      timestamp: new Date().toISOString(),
    });
  }

  /**
   * Called when module is disabled/deactivated.
   * Core modules cannot be fully disabled, but this handles graceful pause.
   */
  async onDisable(): Promise<void> {
    this.log('Media module disable requested (core module - limited action)');

    // Core modules cannot be fully disabled
    // This would only be called during shutdown

    this.initialized = false;
    this.log('Media module disabled');
  }

  /**
   * Called when module is unloaded.
   * Cleans up resources.
   */
  async onUnload(): Promise<void> {
    this.log('Unloading media module...');

    // Clear hooks
    this.hooks = {};

    this.log('Media module unloaded');
  }

  // ---------------------------------------------------------------------------
  // ModuleInstance Interface Methods
  // ---------------------------------------------------------------------------

  /**
   * Returns module routes for registration with Express.
   *
   * @returns Route configuration array
   */
  getRoutes(): unknown[] {
    return [mediaRoutes];
  }

  /**
   * Returns module controllers for registration with routing-controllers.
   *
   * @returns Controller class array
   */
  getControllers(): unknown[] {
    return MediaModule.controllers;
  }

  // ---------------------------------------------------------------------------
  // Hook System
  // ---------------------------------------------------------------------------

  /**
   * Gets current module hooks.
   *
   * @returns Module hooks object
   */
  getHooks(): MediaModuleHooks {
    return { ...this.hooks };
  }

  /**
   * Registers a hook handler.
   *
   * @param hookName - Name of the hook
   * @param handler - Hook handler function
   *
   * @example
   * ```typescript
   * mediaModule.registerHook('afterUpload', async (data) => {
   *   console.log('File uploaded:', data.mediaId);
   * });
   * ```
   */
  registerHook<K extends keyof MediaModuleHooks>(
    hookName: K,
    handler: MediaModuleHooks[K]
  ): void {
    this.hooks[hookName] = handler;
    this.log(`Registered hook: ${hookName}`);
  }

  /**
   * Unregisters a hook handler.
   *
   * @param hookName - Name of the hook to unregister
   */
  unregisterHook(hookName: keyof MediaModuleHooks): void {
    delete this.hooks[hookName];
    this.log(`Unregistered hook: ${hookName}`);
  }

  /**
   * Executes a hook if registered.
   *
   * @param hookName - Name of the hook
   * @param data - Data to pass to the hook
   */
  async executeHook<K extends keyof MediaModuleHooks>(
    hookName: K,
    data: Parameters<NonNullable<MediaModuleHooks[K]>>[0]
  ): Promise<void> {
    const hook = this.hooks[hookName];
    if (hook) {
      try {
        await (hook as (data: typeof data) => Promise<void>)(data);
      } catch (error) {
        this.log(
          `Hook execution error (${hookName}): ${error instanceof Error ? error.message : 'Unknown error'}`
        );
      }
    }
  }

  // ---------------------------------------------------------------------------
  // Event Listeners
  // ---------------------------------------------------------------------------

  /**
   * Sets up event listeners for the media module.
   */
  private setupEventListeners(): void {
    // Listen for organization deletion to clean up media
    this.eventService.on('organization.deleted', async (payload) => {
      this.log(`Organization deleted event received: ${payload.organizationId}`);
      // Could trigger media cleanup for deleted organization
    });

    // Listen for subscription changes that may affect storage limits
    this.eventService.on('subscription.plan.changed', async (payload) => {
      this.log(`Plan changed event received: ${payload.organizationId}`);
      // Could update storage limits based on new plan
    });

    this.log('Event listeners set up');
  }

  // ---------------------------------------------------------------------------
  // Module Settings
  // ---------------------------------------------------------------------------

  /**
   * Gets default module settings.
   *
   * @returns Default media module settings
   */
  static getDefaultSettings(): MediaModuleSettings {
    return {
      maxFileSize: 5 * 1024 * 1024, // 5MB
      allowedMimeTypes: [
        'image/jpeg',
        'image/png',
        'image/webp',
        'image/gif',
      ],
      thumbnailSizes: {
        small: 150,
        medium: 300,
        large: 600,
      },
      storageProvider: 'local',
      cdnEnabled: false,
      autoOptimize: true,
    };
  }

  // ---------------------------------------------------------------------------
  // Utility Methods
  // ---------------------------------------------------------------------------

  /**
   * Logs a message with module prefix.
   *
   * @param message - Message to log
   */
  private log(message: string): void {
    // eslint-disable-next-line no-console
    console.log(`[MediaModule] ${message}`);
  }

  /**
   * Checks if module is initialized.
   *
   * @returns True if module is initialized
   */
  isInitialized(): boolean {
    return this.initialized;
  }

  /**
   * Gets module metadata.
   *
   * @returns Module metadata object
   */
  static getMetadata() {
    return {
      id: MediaModule.id,
      name: MediaModule.name,
      version: MediaModule.version,
      isCore: MediaModule.isCore,
      routes: MediaModule.routes,
      providers: MediaModule.providers.map((p) => p.name),
      controllers: MediaModule.controllers.map((c) => c.name),
    };
  }
}

// -----------------------------------------------------------------------------
// Module Exports
// -----------------------------------------------------------------------------

/**
 * Default export for module loader dynamic import
 */
export default MediaModule;

/**
 * Export module metadata
 */
export const metadata = MediaModule.getMetadata();
